script:
let adults = $.users[*] | where u => u.age >= 18
let admins = adults | where u => u.role == "admin"
return { adultCount: adults | count, adminNames: admins | select u => u.name }

let benefitsFor = memo isFullTime => $.benefits[*] | where b => b.fullTimeOnly == isFullTime | select b => b.name

return $.employees[*] | select e => {
  name: e.name,
  benefits: benefitsFor(e.fullTime)
}

