script:
{
  encoded: $.product.urlEncode(),
  roundtrip: $.product.urlEncode().urlDecode(),
  url: `https://example.com/{$.path.urlEncode()}`
}

$.products[*] | select p => {
  sku: p.sku,
  fullHash: p.sku.hash(),
  shortHash: p.sku.hash(8),
  idempotent: p.sku.hash(8) == p.sku.hash(8)
}

{
  original: $.order.createdAt,
  plusOneDay: $.order.createdAt.add("1.00:00:00"),
  plusProcessing: $.order.createdAt.add($.order.processingTime),
  plus30min: $.order.createdAt.add("00:30:00")
}

{
  formatted: $.event.timestamp.dateFormat("yyyy MMMM dd HH:mm:ss"),
  dateOnly: $.event.timestamp.dateFormat("yyyy-MM-dd"),
  unix: $.event.timestamp.toUnixTimeSeconds(),
  plusOneHour: $.event.timestamp.add("01:00:00").dateFormat("HH:mm:ss")
}

$[*] | select f => {
  file: f.FileName,
  direct: f.LastWriteTimeUtc.toUnixTimeSeconds(),
  viaArg: f.toUnixTimeSeconds(f.LastWriteTimeUtc)
}

$.products[*] | select p => {
  name: p.name,
  isSpecial: p.price > 10 && (p.category == "simple" || p.type == "seasonal")
}

