script:
{
  awayFromZero: $.Qty.toNumber().round("awayFromZero"),
  toEven: $.Qty.toNumber().round("toEven"),
  default: $.Qty.toNumber().round()
}

{
  cloned: $[0].clone(),
  kept: $[*] | skip 1 | take 2 | select o => o.keep("id", "email"),
  removed: $[*] | skip 1 | take 2 | select o => o.remove("profile", "email")
}

{
  slice2to5: $.items[2:5],
  first3: $.items[:3],
  from5: $.items[5:],
  lastTwo: $.items[-2:]
}

{
  default: $.names[*] | concat,
  comma: $.names[*].concat(", "),
  merged: $.names[*].concat("|", $.extras[*], [1, 2])
}

{
  xlsx: $.files[*] | where f => f.name.endsWith(".xlsx") | select f => f.name,
  reports: $.files[*] | where f => f.name.startsWith("report") | select f => f.name,
  finance: $.files[*] | where f => f.path.contains("finance") | select f => f.name
}

let companies = $.foo[*] | select f => f.company

{
  names: $.bar[*] | where b => b.profile.company.in(companies) | select b => b.name
}

{
  sanitizedGerman: $.german.sanitize(),
  sanitizedGreek: $.greek.sanitize(),
  sanitizedAccent: $.accented.sanitize(),
  checks: {
    presentEmpty: $.values.present.isNullOrEmpty(),
    emptyEmpty: $.values.empty.isNullOrEmpty(),
    wsEmpty: $.values.whitespace.isNullOrEmpty(),
    wsWhitespace: $.values.whitespace.isNullOrWhiteSpace(),
    nullEmpty: $.values.nothing.isNullOrEmpty()
  },
  fallbacks: {
    present: $.values.present.isNullOrEmpty("default"),
    empty: $.values.empty.isNullOrEmpty("default"),
    nothing: $.values.nothing.isNullOrEmpty("default")
  }
}

