  "checks": {
    "presentEmpty": false,
    "emptyEmpty": true,
    "wsEmpty": false,
    "wsWhitespace": true,
    "nullEmpty": true
  },
  "fallbacks": {
    "present": "hello",
    "empty": "default",
    "nothing": "default"
  }
}

