  sentence: $.words[*] | reduce (acc, w) => acc + " " + w,
  totalValue: $.orders[*] | reduce (acc, o) => acc + o.qty * o.price from 0
}

{
  static: "fixed",
  [`{$.prefix}_id`]: $.product.id,
  [$.product.season]: "current",
  attributes: $.fields[*] | reduce (acc, f) => { ...acc, [f.name]: f.value } from {}
